+            let mut count = self
+                .inner
+                .receiver_count
+                .lock()
+                .expect("watch lock poisoned");
+            *count += 1;
+        }
+        Self {
+            inner: Arc::clone(&self.inner),
+            seen_version: self.seen_version,
+        }
+    }
