+impl<T> Drop for Receiver<T> {
+    fn drop(&mut self) {
+        let mut count = self
+            .inner
+            .receiver_count
+            .lock()
+            .expect("watch lock poisoned");
+        *count = count.saturating_sub(1);
+    }
