+    guard: RwLockReadGuard<'a, (T, u64)>,
+}
+
+impl<T> std::ops::Deref for Ref<'_, T> {
+    type Target = T;
+
+    fn deref(&self) -> &Self::Target {
+        &self.guard.0
+    }
+}
