+        // Second attempt (first retry)
+        let delay = state.next_attempt(None);
+        assert!(delay.is_some());
+        assert!(delay.unwrap() > Duration::ZERO);
+        assert_eq!(state.attempt, 2);
+        assert!(state.has_attempts_remaining());
