+            RetryFailure::Exhausted(RetryError::new("error", 3, Duration::ZERO));
+        assert!(exhausted.to_string().contains("3 attempts"));
+
+        let cancelled: RetryFailure<&str> = RetryFailure::Cancelled(CancelReason::timeout());
