+
+    #[test]
+    fn timeout_clone_and_copy() {
+        let t1 = Timeout::<()>::new(Time::from_nanos(1000));
+        let t2 = t1; // Copy
+        let t3 = t1; // Also copy (Clone is implied by Copy)
