+
+        let result = oracle.check();
+        assert!(result.is_err());
+
+        let violation = result.unwrap_err();
+        assert_eq!(violation.unrun_finalizers.len(), 2);
+    }
+
+    #[test]
+    fn multiple_regions_independent() {
