+    }
+
+    #[test]
+    fn reset_clears_state() {
+        let mut oracle = LoserDrainOracle::new();
+
+        let race_id = oracle.on_race_start(region(0), vec![task(1), task(2)], t(0));
+        oracle.on_task_complete(task(1), t(50));
+        oracle.on_race_complete(race_id, task(1), t(100));
