+
+    fn task(n: u32) -> TaskId {
+        TaskId::from_arena(ArenaIndex::new(n, 0))
+    }
+
+    fn region(n: u32) -> RegionId {
+        RegionId::from_arena(ArenaIndex::new(n, 0))
+    }
+
+    fn t(nanos: u64) -> Time {
+        Time::from_nanos(nanos)
+    }
+
+    #[test]
+    fn empty_region_passes() {
